server {
    listen 8443 ssl;
    server_name localhost;

    ssl_certificate /etc/nginx/ssl/server.crt;
    ssl_certificate_key /etc/nginx/ssl/server.key;

    # Main branch at root
    location / {
        root /var/www/main;
        index index.html;
        try_files $uri $uri/ =404;
    }

    # Dev branch at /dev/
    location /dev/ {
        alias /var/www/dev/;
        index index.html;
        try_files $uri $uri/ =404;
    }
}
